import React, { useState, useEffect, useCallback } from 'react';
import GameBoard from './GameBoard';
import Score from './Score';
import GameOver from './GameOver';

const GRID_SIZE = 20;
const CELL_SIZE = 20;

const initialSnake = [{ x: 10, y: 10 }];
const initialFood = { x: 15, y: 15 };

const Game: React.FC = () => {
  const [snake, setSnake] = useState(initialSnake);
  const [food, setFood] = useState(initialFood);
  const [direction, setDirection] = useState('right');
  const [gameOver, setGameOver] = useState(false);
  const [score, setScore] = useState(0);

  const moveSnake = useCallback(() => {
    if (gameOver) return;

    setSnake(prevSnake => {
      const newSnake = [...prevSnake];
      const head = { ...newSnake[0] };

      switch (direction) {
        case 'up':
          head.y -= 1;
          break;
        case 'down':
          head.y += 1;
          break;
        case 'left':
          head.x -= 1;
          break;
        case 'right':
          head.x += 1;
          break;
      }

      if (
        head.x < 0 ||
        head.x >= GRID_SIZE ||
        head.y < 0 ||
        head.y >= GRID_SIZE
      ) {
        setGameOver(true);
        return prevSnake;
      }

      if (newSnake.some(segment => segment.x === head.x && segment.y === head.y)) {
        setGameOver(true);
        return prevSnake;
      }

      newSnake.unshift(head);

      if (head.x === food.x && head.y === food.y) {
        setScore(prevScore => prevScore + 1);
        setFood({
          x: Math.floor(Math.random() * GRID_SIZE),
          y: Math.floor(Math.random() * GRID_SIZE),
        });
      } else {
        newSnake.pop();
      }

      return newSnake;
    });
  }, [direction, food, gameOver]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      switch (e.key) {
        case 'ArrowUp':
          if (direction !== 'down') setDirection('up');
          break;
        case 'ArrowDown':
          if (direction !== 'up') setDirection('down');
          break;
        case 'ArrowLeft':
          if (direction !== 'right') setDirection('left');
          break;
        case 'ArrowRight':
          if (direction !== 'left') setDirection('right');
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [direction]);

  useEffect(() => {
    const interval = setInterval(moveSnake, 100);
    return () => clearInterval(interval);
  }, [moveSnake]);

  const resetGame = () => {
    setSnake(initialSnake);
    setFood(initialFood);
    setDirection('right');
    setGameOver(false);
    setScore(0);
  };

  return (
    <div style={{ textAlign: 'center' }}>
      <h1>Snake Game</h1>
      <Score score={score} />
      <GameBoard snake={snake} food={food} gridSize={GRID_SIZE} cellSize={CELL_SIZE} />
      {gameOver && <GameOver score={score} resetGame={resetGame} />}
    </div>
  );
};

export default Game;
EOF

cat > src/components/GameBoard.tsx << 'EOF'
import React from 'react';

interface GameBoardProps {
  snake: Array<{ x: number; y: number }>;
  food: { x: number; y: number };
  gridSize: number;
  cellSize: number;
}

const GameBoard: React.FC<GameBoardProps> = ({ snake, food, gridSize, cellSize }) => {
  const cells = [];
  for (let y = 0; y < gridSize; y++) {
    for (let x = 0; x < gridSize; x++) {
      const isSnake = snake.some(segment => segment.x === x && segment.y === y);
      const isFood = food.x === x && food.y === y;

      cells.push(
        <div
          key={`${x}-${y}`}
          style={{
            width: `${cellSize}px`,
            height: `${cellSize}px`,
            backgroundColor: isSnake ? 'green' : isFood ? 'red' : 'lightgray',
            border: '1px solid gray',
          }}
        />
      );
    }
  }

  return (
    <div
      style={{
        display: 'grid',
        gridTemplateColumns: `repeat(${gridSize}, ${cellSize}px)`,
        gridTemplateRows: `repeat(${gridSize}, ${cellSize}px)`,
        border: '2px solid black',
      }}
    >
      {cells}
    </div>
  );
};

export default GameBoard;
