import { render, screen, fireEvent, act } from '@testing-library/react';
import Game from '../components/Game';

describe('Game', () => {
  it('renders the game', () => {
    render(<Game />);
    expect(screen.getByText('Snake Game')).toBeTruthy();
  });

  it('moves the snake when arrow keys are pressed', () => {
    render(<Game />);
    fireEvent.keyDown(window, { key: 'ArrowUp' });
    expect(screen.getByText('Score: 0')).toBeTruthy();
  });

  it('increases the score when food is eaten', () => {
    render(<Game />);
    fireEvent.keyDown(window, { key: 'ArrowUp' });
    expect(screen.getByText('Score: 1')).toBeTruthy();
  });

  it('shows Game Over when the snake hits the wall', () => {
    render(<Game />);
    fireEvent.keyDown(window, { key: 'ArrowUp' });
    expect(screen.getByText('Game Over!')).toBeTruthy();
  });

  it('resets the game when the Play Again button is clicked', () => {
    render(<Game />);
    fireEvent.keyDown(window, { key: 'ArrowUp' });
    fireEvent.click(screen.getByText('Play Again'));
    expect(screen.getByText('Score: 0')).toBeTruthy();
  });
});
